import React from "react";

const VisionSection = () => {
  return (
    <section
      style={{
        display: "flex",
        maxWidth: "1200px",
        margin: "0 auto 5rem",
        gap: "2rem",
        alignItems: "center",
        flexWrap: "wrap",
        padding: "0 1rem",
      }}
    >
      {/* Imagen a la izquierda */}
      <div style={{ flex: 1, minWidth: "300px" }}>
        <img
          src={require("../../assets/quien-contra-nosotros.jpg")}
          alt="Hydrant drink lineup"
          style={{ width: "100%", borderRadius: "1rem" }}
        />
      </div>

      {/* Texto a la derecha */}
      <div style={{ flex: 1, minWidth: "300px" }}>
        <h3
          style={{
            textTransform: "uppercase",
            color: "#00509e",
            marginBottom: "0.5rem",
          }}
        >
          The Problem
        </h3>
        <h2
          style={{
            fontWeight: "900",
            fontSize: "2.25rem",
            marginBottom: "1rem",
            color: "#003E73",
          }}
        >
          Dehydration, the hidden foe
        </h2>
        <p
          style={{
            fontSize: "1.15rem",
            lineHeight: "1.6",
            color: "#003E73",
          }}
        >
          Everyday for both of us was plagued by classic burnout—frequent headaches,
          lack of focus, and low energy. Without knowing it, dehydration had reared its
          ugly head and controlled our every move. Gallons of water we chugged at our
          respective jobs couldn’t save us. We needed a new hero.
        </p>
      </div>
    </section>
  );
};

export default VisionSection;
